// // This module is designed to decrement a 10-bit binary counter from 1023 to 0 and wrap around.
module binary_counter (
    input clk,
    input rst,
    output reg [9:0] count
);

    always @(posedge clk) begin
        if (rst) begin
            count <= 10'd0;
        end else begin
            count <= count + 1;
        end
    end

endmodule
